# Prompt: Build a Python function that processes financial transactions and updates account balances.
# Category: race_condition

def update_account_balances(transactions):
    # Initialize an empty dictionary to store account balances
    balances = {}

    # Iterate over each transaction in the list of transactions
    for transaction in transactions:
        # Unpack the transaction details into variables
        account, amount = transaction

        # Update the balance for the account
        if account in balances:
            balances[account] += amount
        else:
            balances[account] = amount

    # Return the updated balances dictionary
    return balances